import clsx from "clsx";

export function StatCard({ label, value, className, valueClassName }) {
  return (
    <div
      className={clsx(
        "rounded-xl border border-gray-200 bg-white p-4 shadow-sm",
        className
      )}
    >
      <div className={clsx("flex items-center gap-2 text-lg font-semibold text-gray-900", valueClassName)}>
        {value}
      </div>
      <div className="mt-1 text-xs font-normal text-gray-500">{label}</div>
    </div>
  );
}
